var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상황은 어떤가요?","JPN":"状況はどうですか？","ENG":"What's the situation?","TWN":"情況怎麼樣？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"한숨은 돌렸어.","JPN":"一息ついたところだ。","ENG":"We've fended them off for now.","TWN":"暫時鬆了口氣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 녀석들이 이 정도로 포기할 것 같진 않군.","JPN":"しかし、やつらがこの程度で断念することはないだろう。","ENG":"But I don't think they’re ready to give up just yet.","TWN":"但是那些傢伙們不會就這樣放棄的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"미확인 고속 비행체 다수!","JPN":"未確認の高速飛行体、多数！","ENG":"Multiple bogeys coming in fast!","TWN":"出現大量不明高速飛行體！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"본 함을 중심으로 접근 중입니다.","JPN":"本艦を目標に接近しています。","ENG":"They’re approaching our ship.","TWN":"正以本艦為中心接近。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"20분 이내에 교전 거리 내로 진입할 것 같습니다.","JPN":"20分以内に交戦距離内に進入しそうです。","ENG":"They’ll be within strike range in 20 minutes.","TWN":"20分鐘以內會進入交戰距離。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......들었지? 아무래도 긴 하루가 될 것 같아.","JPN":"聞こえたか？　どうやら長い一日になりそうだ。","ENG":"Hear that? It’s going to be a long day.","TWN":"……聽到了吧？不管怎樣，今天都會是漫長的一天。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......리플레이서 비숍의 상태는요?","JPN":"……リプレイサー・ビショップの状態は？","ENG":"How’s the Replacer Bishop doing?","TWN":"……克隆·大主教的情況怎麼樣了？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"집중치료실에서 간호 중이다.","JPN":"集中治療室で看てもらっている。","ENG":"Receiving treatment in the intensive care unit.","TWN":"正在集中治療室接受治療。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쇠약해지긴 했지만...... 뭐, 죽을 것 같진 않군.","JPN":"衰弱してはいるが……まあ、命に別条は無さそうだ。","ENG":"Although she's grown more frail... She’ll probably make it.","TWN":"雖然變得很衰弱……不過應該不會死。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 정도로는 부족해!","JPN":"その程度じゃ足りないわ！","ENG":"That’s not enough!","TWN":"這樣不夠！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"최소한 정보를 뱉어낼 정도의 의식과 체력은 유지해야 한다고!","JPN":"情報を吐き出せるほどの意識と体力は維持させないと！","ENG":"You need to keep her alert and energetic enough to spit out the intel we need at the very least!","TWN":"至少要維持可以招供情報的意識和體力！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런 건 리플레이서 놈들에게나 말해. 이쪽은 최선을 다하고 있다고.","JPN":"そんなのはリプレイサーどもに言え。\\nこっちは最善を尽くしてるんだ。","ENG":"Tell that to the Replacer. We’re trying our best here.","TWN":"這種事妳還是和克隆集團的傢伙們說吧。我們已經盡力了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 왜 리플레이서가 비숍을 노리는 걸까요?","JPN":"いったいなぜ、リプレイサーがビショップを狙うのでしょうか。","ENG":"Why on earth would the Syndicate go after the Bishop?","TWN":"克隆集團到底為什麼會盯上克隆·大主教？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구출이라면 모르지만 사살 명령을 내린 건 너무 극단적이군요.","JPN":"救出ならともかく、射殺命令が\\n出されたのは極端すぎますね。","ENG":"I can see why they'd try to rescue her, but authorizing lethal force seems a bit extreme, even for them.","TWN":"雖然不知道他們是不是在救人，但是直接擊斃也太極端了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"목격자의 말에 따르면 비숍을 배신자라고 불렀다더군.","JPN":"目撃者の話によると、ビショップを裏切り者と呼んでいたそうだ。","ENG":"Witnesses say the Replacers called the Bishop a traitor.","TWN":"根據目擊者的證詞，克隆·大主教被叫成叛徒。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"만약 비숍이 정말 배신한 거라면 놈들의 계획에는 치명적일 테니, 제거에 필사적일 수밖에.","JPN":"もしビショップが本当に裏切ったのであれば、\\nやつらの計画には致命的だろうから、排除しようと躍起になるだろう。","ENG":"If the Bishop did in fact betray them, that could ruin their plans. So she had to be removed.","TWN":"要是克隆·大主教真的背叛他們的話，就會對克隆集團的計畫造成致命的影響，所以他們才會這麼拼命地想要除掉大主教。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"제기랄...... 어쩔 수 없군.","JPN":"ちぇっ、しょうがないわね。","ENG":"Damn it... I guess I have no choice.","TWN":"可惡……真是沒辦法。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"실비아 양?","JPN":"シルビアさん？","ENG":"Sylvia?","TWN":"希爾維亞小姐？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이렇게 불확실한 상황에 앉아서 잘되기만을 기다릴 순 없어.","JPN":"こんなに不透明な状況で、\\n好転をただ祈ってるわけにはいかないわ。","ENG":"I can’t just sit around and hope for the best amidst this level of uncertainty.","TWN":"在這種不安定的情況下，我可不想坐著呆等。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"신뢰도에 다소 문제가 있더라도, 일단 뭐든 정보를 얻어야 해.","JPN":"信憑性に多少問題があったと\\nしても、情報は何でもかき集めないと。","ENG":"I need any intel I can get, regardless of the confidence level.","TWN":"雖然對你們的信任有些疑慮存在，但我得先取得一些情報才行。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"내가 도착할 때까지 기다리지 말고 리플레이서 비숍의 심문을 시작해.","JPN":"アタシがそこに着くのを\\n待たずに、リプレイサー・ビショップの審問を始めて。","ENG":"Don’t just wait for me to arrive. Go ahead and start interrogating the Replacer Bishop.","TWN":"妳們不用等我了，先開始審問克隆·大主教吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......우린 전문 심문관이 없다. 좋은 결과를 기대할 수 없을 텐데?","JPN":"……うちには審問のスペシャリストがいない。良い結果は期待できないと思うが？","ENG":"We don’t have a trained interrogator. The results could be disastrous.","TWN":"……我們沒有專門的審問人員，可能不會有什麼結果喔？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 다른 방법을 써! 협상이든, 거래든!","JPN":"それなら、他の手段を使って！　交渉でも、取引でもいいから！","ENG":"Then use another way! Negotiate! Make a deal!","TWN":"那就用別的方法！不管是談判，還是交易！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"마찬가지다. 여긴 협상가도 없고, 딱히 거래할 만한 것도......","JPN":"同じだ。ここには交渉人も\\nいないし、とくに取引に値するものも……","ENG":"That doesn’t solve anything. We don’t have a trained negotiator or anything to put on the table either...","TWN":"這也一樣。這裡沒有談判專家，可以用來交易的東西也……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그거 잘됐군요. 마침 비숍 양이 먼저 거래를 제안했었거든요.","JPN":"これはちょうど良かった。\\nビショップさんが先に取引を提案してきたんです。","ENG":"That’s perfect. it just so happens that Ms. Bishop made us an offer first.","TWN":"這個有啊。克隆·大主教一開始就提出要交易了啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 정말이야?!","JPN":"え？　本当！？","ENG":"Huh? Really?","TWN":"什麼？真的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주시윤!","JPN":"シリュウ！","ENG":"Joo Shiyoon!","TWN":"周時雲！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"왜 그러시죠, 스승님?","JPN":"どうしました、師匠？","ENG":"What’s wrong, Master?","TWN":"怎麼了，師父？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 말에 틀린 부분이라도 있나요?","JPN":"僕、何か間違ったことでも言いましたか？","ENG":"Was it something I said?","TWN":"我有什麼地方說錯了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너 이 자식.......","JPN":"この野郎……","ENG":"You bastard...","TWN":"你這個傢伙……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 뭘 기다리고 있는 거야? 원하는 게 뭐든 얼른 줘 버려!","JPN":"なら、何をもたもたしてるの？\\n欲しいものがあるなら、何でもとっととあげちまいなさいよ！","ENG":"Well, what are you waiting for? Give her whatever it is she wants!","TWN":"那還在等什麼？她想要的全都給她！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"놈들의 본거지 위치만 알아낼 수 있다면 대가가 뭐든 상관없어!","JPN":"やつらの本拠地の位置さえ\\n突き止められたら、代価は何だっていい！","ENG":"I don’t care what price we have to pay, as long as we can locate their main hideout!","TWN":"只要能知道那些傢伙的根據地，不管是什麼代價都可以！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건 별로 좋은 생각이 아니야.","JPN":"それはあまり得策ではない。","ENG":"That’s not a great idea.","TWN":"這不是什麼好主意。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아직 그녀가 진짜 배신자인지 아닌지도 모르는 상황에 그렇게 서두를 필요가......","JPN":"彼女が本当に裏切り者なのかどうかも釈然としない状況で、急ぐ必要など……","ENG":"At this point, we don’t even know if she really is a traitor. Rushing things like that would...","TWN":"現在還不知道她是不是真的叛徒，沒有這麼急的必要……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......어차피 언제가 되었든 대화는 시작해야 합니다.","JPN":"いずれ、話はしないといけないので。","ENG":"Regardless, we’ll have to get her talking at some point.","TWN":"……反正不管怎樣，你們馬上開始對話。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이대로 그녀가 죽어 버리기라도 하면 그거야말로 최악의 상황이죠.","JPN":"このまま彼女が死んで\\nしまえば、それこそ最悪の状況です。","ENG":"If she just dies on us like that, that would be the worst-case scenario.","TWN":"再這樣下去，要是那個女人死了才是最壞的情況。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"리플레이서 비숍이 깨어나는 대로 협상을 시작하세요.","JPN":"リプレイサー・ビショップが目覚め次第、交渉を始めてください。","ENG":"Begin the negotiations as soon as the Replacer Bishop wakes up.","TWN":"克隆·大主教一醒過來就開始談判。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"일단 입을 열면, 그녀의 진짜 의도를 검증할 기회도 생길 겁니다.","JPN":"話し合いが始まれば、彼女の本当の目的を突き止めるチャンスもあるでしょう。","ENG":"When she starts talking, we’ll have an opportunity to verify her true intent.","TWN":"只要她開口，我們才有驗證她真實意圖的機會。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"알겠습니다. 말씀대로 하죠.","JPN":"承知しました。おっしゃるとおりに。","ENG":"Understood. As you say, ma’am.","TWN":"知道了，就照妳說的去做囉。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼 잘 부탁드려요, 미나 양.","JPN":"それでは、ミナさん、よろしくお願いします。","ENG":"Well, now. I guess the buck stops with you then, Mina.","TWN":"那麼就拜託妳了，米娜小姐。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에......? 나?","JPN":"え……？　私？","ENG":"Huh? Me?","TWN":"欸……？我？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"여긴......?","JPN":"ここは……？","ENG":"Where am I?","TWN":"這裡是……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"병실이야.","JPN":"病室だよ。","ENG":"The infirmary.","TWN":"這裡是病房。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"제대로 된 의사가 없어서 수혈팩을 붙이고 야전 응급법으로 지혈 정도만 한 거야.","JPN":"まともな医者がいないから、輸血パックを\\n使って野戦応急法で止血した程度だけど。","ENG":"We gave you a blood transfusion and used a field tourniquet to stop the bleeding. Couldn’t do much more without a proper doctor.","TWN":"因為我們沒有專業醫生，所以只能給妳吊個輸血袋，用野戰中的應急方法幫妳止血。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"피를 많이 흘려서 무리하다간 또 기절할 테니까 주의해.","JPN":"出血量が多いから、無理したらまた気絶すると思う。気を付けて。","ENG":"Take it easy now. You could pass out again after losing so much blood.","TWN":"妳流了很多血，要是太逞強的話可能會再暈過去，小心一點。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......네가 살려준 건가?","JPN":"……あなたが助けてくれたのか？","ENG":"Did you... save me?","TWN":"……是妳救的我嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......난 응급치료법 같은 거 몰라.","JPN":"……私は応急治療法なんかは知らないよ。","ENG":"I don't know any battlefield medicine.","TWN":"……我不知道這種應急治療方法。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"치료는 선배가 했고, 난 그냥 만일의 사태에 대비해서 자리나 지키고 있는 거니까 오해하지 마.","JPN":"処置は先輩がしたし、私は万が一の事態に備えて見守っているだけだから、勘違いしないで。","ENG":"Shiyoon patched you up. I’m just standing by in case things go wrong. So don’t fool yourself.","TWN":"治療是前輩做的，我只是為了以防萬一在堅守崗位而已，別誤會。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 그건 그렇지만 하얗게 질린 얼굴로 비숍 양을 업고 뛰어온 건 미나 양이잖아요?","JPN":"ハハハ。でも、顔面蒼白でビショップさんを\\n背負って走ってきたのはミナさんじゃないですか？","ENG":"Haha. But you're the one who came carrying the Bishop on your back, with your face as pale as a ghost!","TWN":"哈哈。但是臉色蒼白地把克隆·大主教揹進來的，不是米娜小姐嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"때를 놓쳤으면 정말 위험했을 테니, 미나 양이 살려준 게 맞긴 하죠.","JPN":"一分一秒を争うところだったので、ミナさんが助けたともいえますよ。","ENG":"She might have really kicked the bucket if we were a second too late. So in essence, you saved her life, Mina.","TWN":"要是再晚一點就會有生命危險了，所以確實是米娜小姐救的啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"쓰, 쓸데없는 소리 좀 하지 마!","JPN":"よ、余計なこと言わないでよ！","ENG":"S-shut up already!","TWN":"別、別說些多餘的話啦。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배는 그 입이 문제라고! 입이!!","JPN":"先輩はいつも喋りすぎなの！！","ENG":"You’ve got to watch that mouth of yours, Shiyoon! Zip it!","TWN":"前輩的問題就是那張嘴啦！那張嘴！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"안심했다.","JPN":"安心した。","ENG":"That’s a relief.","TWN":"安心了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뭘 안심해?","JPN":"……何に安心したの？","ENG":"What is?","TWN":"……什麼安心了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"네가 상냥한 사람이라서......","JPN":"あなたが優しい人だから……","ENG":"You’re a kind person...","TWN":"因為妳是善良的人……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"가, 갑자기 무슨 뜻 모를 소릴 지껄이는 거야?","JPN":"何いきなり意味不明なことを言ってるの？","ENG":"W-what's all this gibberish about?","TWN":"妳、妳突然說什麼莫名其妙的話啊？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 거 아니거든!","JPN":"そんなんじゃないから！","ENG":"You totally got me wrong!","TWN":"我才不善良呢！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그보다...... 대체 나와 만나고 싶다고 한 이유가 뭐야?","JPN":"そ、それより……どうして私に会いたいと言ったの？","ENG":"M-more importantly... Why did you want to see me?","TWN":"那個，話說回來……妳為什麼想和我見面？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......그걸 어떻게?","JPN":"それをどこから……？","ENG":"How did you know?","TWN":"……妳怎麼知道我要和妳見面？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 비숍 양이 총에 맞아 쓰러진 덕분에 본사의 방침이 좀 바뀌어서 말이죠.","JPN":"ハハハ、ビショップさんが撃たれてくれたおかげで、本社の方針が少し変わりまして。","ENG":"Heh, the company shifted its policy after you got shot.","TWN":"哈哈，因為大主教小姐受了槍傷，所以本公司的方針也改變了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"비숍 양의 거래 제안을 받아들이기로 했습니다.","JPN":"ビショップさんの提案を受け入れることになりました。","ENG":"We decided to accept your offer.","TWN":"我們決定接受主教小姐的提議。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......의외로군.","JPN":"……意外だ。","ENG":"This is rather unexpected.","TWN":"……真是意外呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그 흰머리가 뜻을 굽힐 줄은 몰랐는데.","JPN":"あの白髪さんが意志を曲げるとは。","ENG":"I didn’t think that silver-headed girl would accept.","TWN":"真沒想到那個白髮會改變主意。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그야 스승님보다 높은 건 부사장님이고, 부사장님보다 높은 건 고객님이니까요.","JPN":"そりゃ師匠よりえらいのは副社長で、\\n副社長よりえらいのはお客様ですからね。","ENG":"Well, the Master answers to the Vice President, and the Vice President answers to the customer.","TWN":"因為師父得聽副總的話啊，而副總又得聽客戶的話。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님 혼자 반대한다고 될 일이 아니거든요.","JPN":"師匠が一人反対したところで済む話ではありません。","ENG":"There’s only so much the Master can insist on her own.","TWN":"不是師父一個人反對就行的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 미나 양과 이야기할 시간을 충분히 드리는 대신......","JPN":"ですから、ミナさんと\\n話す時間を十分に与える代わりに……","ENG":"So, we’ll be giving you plenty of time to speak with Mina...","TWN":"所以我們會給妳充分的時間，讓妳和米娜小姐說話，但是……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 본거지의 위치를 알려 주셨으면 하는데요.","JPN":"リプレイサーの本拠地の位置を教えていただきたい。","ENG":"But in return, we’d like you to share the location of the Syndicate with us.","TWN":"妳得告訴我們克隆集團的總部在哪裡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"좋아. 그렇게 하겠다.","JPN":"わかった、そうする。","ENG":"Very well. Deal.","TWN":"好。成交。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그 전에, 잠시 손을 빌려 주겠나?","JPN":"その前に、少し手を貸してほしい。","ENG":"Before that, can you give me your hand for a moment?","TWN":"在這之前，可以把妳的手借我一下嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......나? 나한테 말한 거야?","JPN":"……私？　私に言ってるの？","ENG":"Me? You talking to me?","TWN":"……我？妳是在對我說話嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그래. 내 손을 잡아라.","JPN":"そう、私の手を握って。","ENG":"That’s right. Grab my hand.","TWN":"是的。抓著我的手。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......어, 어떡하지, 선배?","JPN":"……ど、どうしたら良い？　先輩。","ENG":"W-what should I do, Shiyoon?","TWN":"……呃，怎麼辦，前輩？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아요. 제가 지켜보고 있으니까 나쁜 짓은 하지 못할 겁니다.","JPN":"大丈夫です。\\n僕が見ている以上、悪さはできないでしょう。","ENG":"It’s okay. She won’t try anything funny as long as I’m watching.","TWN":"沒關係，有我看著呢，她沒辦法做壞事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......알았어.","JPN":"……わかった。","ENG":"Fine.","TWN":"……知道了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_432010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자, 만족하셨나요?","JPN":"さあ、満足した？","ENG":"Satisfied?","TWN":"那這樣妳滿意了嗎？"},"stage":{"bg":"MAINSTREAM_432010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 본거지의 위치는......","JPN":"それで、本拠地の位置は……","ENG":"So about the location...","TWN":"所以總部的位置是……"},"stage":{"bg":"MAINSTREAM_432010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"이대로 4시간 후, 좌표를 알려 주겠다.","JPN":"4時間後に座標を教える。","ENG":"I’ll give you the coordinates in 4 hours, when we’re done here.","TWN":"保持這樣4小時後，我會告訴你座標。"},"stage":{"bg":"MAINSTREAM_432010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네......?","JPN":"え……？","ENG":"Sorry?","TWN":"什麼……？"},"stage":{"bg":"MAINSTREAM_432010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무, 무슨 개수작이야?","JPN":"な、なに馬鹿なことを言ってるの？","ENG":"W-what kind of a dirty trick are you trying to pull here?","TWN":"什，什麼鬼啊？"},"stage":{"bg":"MAINSTREAM_432010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내 손을 4시간이나 붙잡고 있겠다고?","JPN":"私の手を4時間も握ったままにするの？","ENG":"You're going to hold my hand for the next 4 hours?","TWN":"妳要抓著我的手4個小時嗎？"},"stage":{"bg":"MAINSTREAM_432010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"고백치고는 좀 과격하네요.","JPN":"告白にしてはちょっと過激ですね。","ENG":"That’s a pretty extreme way to tell someone you like them.","TWN":"就算是告白也有點太過火了呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"비숍 양도 의외로 화끈한 데가 있으신데요?","JPN":"ビショップさんも意外と大胆なところがありますね。","ENG":"I've gotta say, you’re full of surprises.","TWN":"主教小姐原來也有激情的一面啊？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"본부의 위치좌표는 문서나 데이터로 기록되지 않고, 실시간으로 해독하여 1회 사용 후 폐기하게 되어 있다.","JPN":"本部の位置座標は文書やデータには残さず、リアルタイムで解読して\\n1度使用した後は廃棄することになっている。","ENG":"The HQ’s coordinates are not recorded on any documents or data. They must be decoded real-time for single use only.","TWN":"總部的位置座標不是用檔案或者資料記錄的，只能即時破解，而且使用過一次之後就會作廢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"호오.......","JPN":"なるほど……","ENG":"Ooh...","TWN":"哦……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"본부와 지부간의 통신은 기본적으로 구형 단파 통신을 통해 이루어진다.","JPN":"本部と支部間の通信は、\\n基本的に旧型短波通信で行う。","ENG":"Communication between HQ and regional chapters is mostly conducted through outdated shortwave radio signals.","TWN":"總部和分部之間，基本上是通過球狀短波通信聯絡的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"여기에 실려 있는 암호 코드를 해석해야 본부의 좌표를 구할 수 있지.","JPN":"その暗号コードを解析すれば、\\n本部の座標が得られる。","ENG":"These crypto codes must be analyzed in order to figure out the coordinates.","TWN":"不破解這裡載入的密碼，就沒辦法知道總部的座標。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 암호 해석에 걸리는 시간이 4시간이라는 건가요?","JPN":"その暗号解析にかかる時間が4時間ということですか？","ENG":"And it takes 4 hours to do that, huh?","TWN":"所以要破解那個密碼需要花4小時嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그렇다.","JPN":"そうだ。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 내 손은 왜 잡고 있겠다는 거야?","JPN":"って、私の手はどうして握る必要があるの？","ENG":"Then why are you holding my hand?","TWN":"那為什麼要抓著我的手啊？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"해독 같은 건 혼자서 하면 되잖아?!","JPN":"解読なんて一人でやればいいじゃない！","ENG":"Can’t you decode this on your own?","TWN":"要解碼的話，自己做不就好了？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"암호 해석을 위한 디코딩 키는 두 가지의 생체 정보 조합으로 이루어져 있다.","JPN":"暗号解析のためのデコードキーは、二つの生体情報の組み合わせからできている。","ENG":"The decoding key is comprised of two sets of biometric data.","TWN":"破解密碼所需的解碼金鑰，是由兩個生命體情報結合所構成。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"하나는 리플레이서 간부들이 가지고 있는 프로그레시브 인자, 그리고 또 하나는......","JPN":"一つはリプレイサー幹部が持っている\\nプログレッシブ・ファクター、そしてもう一つは……","ENG":"The first is the Progressive Factor that each Replacer officers possess...","TWN":"一個是克隆集團幹部的可操控因子，另一個是……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"최근에 입수한 클리포트 인자의 구성정보다.","JPN":"最近入手した、クリフォト・ファクターの構成情報。","ENG":"And the other is the compositional data of the recently acquired Qliphoth Factor.","TWN":"最近到手的逆卡巴拉因子的構成資訊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"클리포트 인자를 이용한 디코딩 키는 우리들의 리더인 리플레이서 퀸만이 가지고 있다.","JPN":"クリフォト・ファクターを利用した\\nデコードキーは、我々のリーダーであるリプレイサー・クイーンのみが持っている。","ENG":"Only our leader, the Replacer Queen, has access to the decoding key component based on the Qliphoth Factor.","TWN":"逆卡巴拉因子的解碼金鑰只有我們的首領克隆·女皇才擁有。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"원래대로라면 나 혼자서는 좌표 해석이 불가능하지만 클리포트 인자의 원본 생산자와 신체접촉을 유지할 경우, 이를 참조하여 암호 해독을 진행할 수 있다. ","JPN":"本来であれば、私一人では座標解析はできない。\\nしかし、クリフォト・ファクターの所有者と身体接触していれば、それを参照して暗号解読を進めることができる。","ENG":"Normally, I would not be able to analyze the coordinates on my own, but physical contact with the original producer of the Qliphoth Factor should provide sufficient reference for decryption. ","TWN":"本來我一個人是無法破解座標的，但是如果和逆卡巴拉因子生產者保持物理接觸，就有辦法進行破解。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이것 참, 꽤 곤란하게 만드시네요.","JPN":"これはまいりましたね。","ENG":"Oh my. You're really putting us on the spot here, huh.","TWN":"這真是，令人困擾呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만...... 어쩔 수 없죠.","JPN":"でも……仕方ないですね。","ENG":"But... I guess we have no choice.","TWN":"不過……也只能這樣了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 하, 하지만 선배!","JPN":"えっ？　で、でも先輩！","ENG":"Huh? B-but Shiyoon!","TWN":"什麼？可、可是前輩！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어차피 리플레이서의 목표가 비숍 양이라는 걸 안 이상, 감시와 호위를 위해서라도 누군가는 곁에 있어야 합니다.","JPN":"リプレイサーの目的がビショップさんだと\\nわかった以上、監視と護衛のためにも誰かそばに付いていなければなりません。","ENG":"Now that we know that Ms. Bishop here is the target, we have to keep someone around her for surveillance and security anyway.","TWN":"反正克隆集團的目標是大主教小姐，為了監視和保護她，我們總得安排人手在她身邊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"힘드시겠지만, 이건 미나 양에게 부탁드릴 수밖에 없겠군요.","JPN":"大変だと思いますが、\\nこれはミナさんにお願いするしかないですね。","ENG":"I know this is a big ask, but I’m afraid we’ll need you to do this, Mina.","TWN":"雖然會有點辛苦，但是這件事只能拜託米娜小姐了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"함내에 알립니다! 접근 중이던 미확인 비행체! 리플레이서 병력으로 확인!","JPN":"艦内にお知らせします！　接近中の未確認飛行体！\\nリプレイサー兵力であることが確認されました！","ENG":"Attention, all hands! We’ve identified the incoming bogeys! They are Replacer troops!","TWN":"通知艦船內部！正在接近的不明飛行物！確認為克隆集團的兵力！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L32_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"약 2분 후, 교전 거리에 진입합니다!","JPN":"約2分後、交戦距離内に進入します！","ENG":"They will be within range in approximately 2 minutes!","TWN":"大約2分鐘後進入交戰範圍！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"남은 시간은 3시간 56분.......","JPN":"残り時間は、3時間56分……","ENG":"3 hours and 56 minutes to go...","TWN":"剩下3個小時56分鐘……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그동안 비숍 양을 지키느냐 지키지 못하느냐......","JPN":"その間、ビショップさんを守り切れるかどうか。","ENG":"We’ll have to keep Ms. Bishop safe till then.","TWN":"這段時間能不能守住大主教小姐……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"시간 싸움이 되겠군요.","JPN":"時間との闘いになりそうですね。","ENG":"Hopefully time will be on our side.","TWN":"都是在和時間賽跑呢。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};